package main

import (
    "html/template"
    "net/http"

    "github.com/gorilla/mux"
)

type Comment struct {
    Name string
    Body string `json:"body"`
}

var comments = []Comment{
    {Name: "John", Body: "Hello World!"},
    {Name: "Alice", Body: "This is a **bold** and *italic* text."},
    {Name: "Bob", Body: "I love Go programming language."},
}

func CommentHandler(w http.ResponseWriter, r *http.Request) {
    tmpl := template.Must(template.ParseFiles("comment.html"))
    err := tmpl.Execute(w, comments)
    if err != nil {
        http.Error(w, err.Error(), http.StatusInternalServerError)
    }
}

func main() {
    router := mux.NewRouter()
    router.HandleFunc("/comments", CommentHandler).Methods("GET")
    http.ListenAndServe(":8080", router)
}